SELECT ?performance ?created WHERE {
  ?performance efrbroo:R20_recorded ?recorded_by .
  FILTER(CONTAINS(STR(?recorded_by), "Radio France"))
  ?performance efrbroo:R17_created ?created .
  FILTER(YEAR(?created) = 2014)
} LIMIT 10

